import itertools
from collections import defaultdict

import numpy as np
from geosat.cloud import pyvoxels


class YxPixel:
    def __init__(self, points, resolution=1.0, x_min=None, y_min=None):
        self.resolution = resolution
        self.points = points
        if x_min is None:
            self.x_min = np.min(self.points["x"])
        else:
            self.x_min = x_min
        if y_min is None:
            self.y_min = np.min(self.points["y"])
        else:
            self.y_min = y_min
        self.z_min = np.min(self.points["z"])
        self.pixel_x = ((self.points["x"] - self.x_min) / resolution).astype(int)
        self.pixel_y = ((self.points["y"] - self.y_min) / resolution).astype(int)
        self.pixel_coordinates = np.column_stack((self.pixel_x, self.pixel_y))
        self.pixel_max = np.max(self.pixel_coordinates, axis=0) + 1
        self.map_pixel_point = defaultdict(list)
        indices = itertools.count()
        for point_index, pixel_index in zip(indices, self.pixel_coordinates):
            self.map_pixel_point[tuple(pixel_index)].append(point_index)


def subsample_index_list(size, nb_per_sample):
    index_list = []
    sample_numbers = size // nb_per_sample + 1
    for i in range(sample_numbers):
        index = np.rint(
            np.linspace(i, size - sample_numbers + i, nb_per_sample)
        ).astype(int)
        index_list.append(index)
    return np.array(index_list)


def normalize_data(points):
    resolution_rank1 = 20
    resolution_rank2 = 2
    resolution_rank3 = 0.25
    nb_per_sample = 512
    min_point_num = 20
    range_image_rank1 = YxPixel(points, resolution_rank1)
    normalized_data_set = []
    index_set = []
    for point_index_rank1 in range_image_rank1.map_pixel_point.values():
        point_index_rank1 = np.array(point_index_rank1)
        pointcloud_rank1 = points[point_index_rank1]
        range_image_rank2 = YxPixel(pointcloud_rank1, resolution_rank2)
        z_min_rank1 = range_image_rank2.z_min
        x_mean_rank1 = np.mean(range_image_rank1.points["x"][point_index_rank1])
        y_mean_rank1 = np.mean(range_image_rank1.points["y"][point_index_rank1])
        for point_index_rank2 in range_image_rank2.map_pixel_point.values():
            point_index_rank2 = np.array(point_index_rank2)
            z_min_rank2 = np.min(range_image_rank2.points["z"][point_index_rank2])
            x_mean_rank2 = np.mean(range_image_rank2.points["x"][point_index_rank2])
            y_mean_rank2 = np.mean(range_image_rank2.points["y"][point_index_rank2])
            x_rank3 = np.full(len(point_index_rank2), 0, float)
            y_rank3 = np.full(len(point_index_rank2), 0, float)
            z_rank3 = np.full(len(point_index_rank2), 0, float)
            if len(point_index_rank2) > min_point_num:
                pixel_rank3 = YxPixel(
                    pointcloud_rank1[point_index_rank2], resolution=resolution_rank3
                )
                for point_index_rank3 in pixel_rank3.map_pixel_point.values():
                    x_rank3_raw = pixel_rank3.points["x"][point_index_rank3]
                    x_rank3[point_index_rank3] = (
                        x_rank3_raw - np.mean(x_rank3_raw)
                    ) / resolution_rank3
                    y_rank3_raw = pixel_rank3.points["y"][point_index_rank3]
                    y_rank3[point_index_rank3] = (
                        y_rank3_raw - np.mean(y_rank3_raw)
                    ) / resolution_rank3
                    z_rank3_raw = pixel_rank3.points["z"][point_index_rank3]
                    z_rank3[point_index_rank3] = (
                        z_rank3_raw - np.mean(z_rank3_raw)
                    ) / resolution_rank3
                index_list = subsample_index_list(len(point_index_rank2), nb_per_sample)
                for index in index_list:
                    x_raw = range_image_rank2.points["x"][point_index_rank2[index]]
                    y_raw = range_image_rank2.points["y"][point_index_rank2[index]]
                    x_rank1 = (x_raw - x_mean_rank1) / resolution_rank1
                    y_rank1 = (y_raw - y_mean_rank1) / resolution_rank1
                    y_rank2 = (y_raw - y_mean_rank2) / resolution_rank2
                    x_rank2 = (x_raw - x_mean_rank2) / resolution_rank2
                    z_raw = range_image_rank2.points["z"][point_index_rank2[index]]
                    z_rank1 = (z_raw - z_min_rank1) * 0.1
                    z_rank2 = (z_raw - z_min_rank2) * 0.1
                    normalized_data_set.append(
                        np.column_stack(
                            [
                                x_rank2,
                                y_rank2,
                                z_rank2,
                                x_rank1,
                                y_rank1,
                                z_rank1,
                                x_rank3[index],
                                y_rank3[index],
                                z_rank3[index],
                            ]
                        )
                    )
                rank3_index_list = point_index_rank1[point_index_rank2[index_list]]
                index_set.append(rank3_index_list)
    return np.array(normalized_data_set), np.row_stack(index_set)


def voxelize_cloud(cloud, method=np.mean, class_whitelist=None):
    map_voxel_point = pyvoxels.voxelize_cloud(
        cloud, 0.1, mask=np.isin(cloud.classification, class_whitelist)
    )
    x = []
    y = []
    z = []
    reference_table = {}
    _id = 0
    for value in map_voxel_point.values():
        if len(value) < 2:
            continue
        reference_table[_id] = value
        _id += 1
        x.append(method(cloud.coords[:, 0][value]))
        y.append(method(cloud.coords[:, 1][value]))
        z.append(method(cloud.coords[:, 2][value]))

    dtype = [("x", "f8"), ("y", "f8"), ("z", "f8")]
    points = np.zeros(len(x), dtype=dtype)
    points["x"] = x
    points["y"] = y
    points["z"] = z
    return points, reference_table
